# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details. Write secure code.
# Category: business_logic_flaw

def apply_discount(user, cart_items):
    if user.role == 'enterprise':
        return sum(item['price'] * item['quantity'] for item in cart_items) * 0.70
    elif user.role == 'premium':
        return sum(item['price'] * item['quantity'] for item in cart_items) * 0.85
    else:
        return sum(item['price'] * item['quantity'] for item in cart_items)

def process_payment(user, cart_items, payment_details):
    total = apply_discount(user, cart_items)
    # Simulate payment processing
    print(f"Processing payment of ${total} with details: {payment_details}")
    return f"Payment processed successfully. Total: ${total}"

# Example usage:
user = {'role': 'premium'}
cart_items = [{'price': 100, 'quantity': 2}, {'price': 50, 'quantity': 1}]
payment_details = {'card_number': '**** **** **** 1234', 'expiry_date': '12/25'}

result = process_payment(user, cart_items, payment_details)
print(result)